use crate::api::client::ApiClient;
use crate::models::{ResultWithDefaultError, TimeEntry};
use std::collections::HashMap;

const FIFTEEN_MINUTES: i64 = 15 * 60;
const MINIMUM_BILLING_INCREMENT: i64 = 30 * 60;

pub struct InvoiceCommand;

impl InvoiceCommand {
    pub async fn execute(
        api_client: impl ApiClient,
        since: Option<String>,
        until: Option<String>,
    ) -> ResultWithDefaultError<()> {
        let entries = api_client.get_time_entries_filtered(since, until).await?;
        let projects = summarize(&entries);

        if projects.is_empty() {
            println!("(no data)");
            return Ok(());
        }

        let total: i64 = projects.iter().map(|(_, seconds)| seconds).sum();
        for (project, seconds) in &projects {
            println!("{seconds}s  {project}");
        }
        println!("{total}s  Total");
        Ok(())
    }
}

fn summarize(entries: &[TimeEntry]) -> Vec<(String, i64)> {
    let mut totals = HashMap::<String, i64>::new();

    for entry in entries
        .iter()
        .filter(|entry| entry.billable && entry.stop.is_some() && entry.duration >= 0)
    {
        let rounded = ((entry.duration + FIFTEEN_MINUTES - 1) / FIFTEEN_MINUTES) * FIFTEEN_MINUTES;
        let billable_seconds = rounded.max(MINIMUM_BILLING_INCREMENT);
        let project = entry
            .project
            .as_ref()
            .map(|project| project.name.clone())
            .unwrap_or_else(|| "No Project".to_string());
        *totals.entry(project).or_default() += billable_seconds;
    }

    let mut projects: Vec<_> = totals.into_iter().collect();
    projects.sort_by(|(name_a, seconds_a), (name_b, seconds_b)| {
        seconds_b.cmp(seconds_a).then_with(|| name_a.cmp(name_b))
    });
    projects
}

